import logging
import json
import os
import azure.functions as func

# Define allowed origins explicitly instead of using wildcard "*"
# This prevents unauthorized domains from making cross-origin requests
ALLOWED_ORIGINS = os.environ.get(
    "ALLOWED_ORIGINS",
    "https://myapp.azurewebsites.net,https://staging.myapp.azurewebsites.net"
).split(",")

# Allowed methods and headers for CORS
ALLOWED_METHODS = ["GET", "POST", "PUT", "DELETE", "OPTIONS"]
ALLOWED_HEADERS = ["Content-Type", "Authorization", "X-Requested-With"]

app = func.FunctionApp()


def get_cors_origin(request_origin: str) -> str:
    """
    Validate the request origin against the allowlist.
    Returns the origin if allowed, otherwise returns empty string.
    This prevents reflecting arbitrary origins which is equivalent to wildcard CORS.
    """
    if request_origin and request_origin.strip() in [o.strip() for o in ALLOWED_ORIGINS]:
        return request_origin.strip()
    return ""


def add_cors_headers(req: func.HttpRequest, response: func.HttpResponse) -> func.HttpResponse:
    """
    Add CORS headers to the response based on validated origin.
    Only reflects origins that are in the explicit allowlist.
    """
    request_origin = req.headers.get("Origin", "")
    validated_origin = get_cors_origin(request_origin)

    if validated_origin:
        response.headers["Access-Control-Allow-Origin"] = validated_origin
        response.headers["Access-Control-Allow-Methods"] = ", ".join(ALLOWED_METHODS)
        response.headers["Access-Control-Allow-Headers"] = ", ".join(ALLOWED_HEADERS)
        response.headers["Access-Control-Max-Age"] = "600"
        # Vary header is important when origin is not wildcard to ensure
        # caches differentiate responses by origin
        response.headers["Vary"] = "Origin"
        # Only set Allow-Credentials when we have a validated specific origin
        response.headers["Access-Control-Allow-Credentials"] = "true"

    return response


def create_json_response(data: dict, status_code: int = 200) -> func.HttpResponse:
    """Create a JSON HTTP response with proper content type."""
    return func.HttpResponse(
        body=json.dumps(data),
        status_code=status_code,
        mimetype="application/json"
    )


@app.route(route="api/data", methods=["GET", "OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def get_data(req: func.HttpRequest) -> func.HttpResponse:
    """
    GET /api/data - Returns sample data for the SPA.
    Handles CORS preflight (OPTIONS) and actual GET requests.
    """
    logging.info("Processing GET /api/data request")

    # Handle CORS preflight request
    if req.method == "OPTIONS":
        response = func.HttpResponse(status_code=204)
        return add_cors_headers(req, response)

    try:
        data = {
            "items": [
                {"id": 1, "name": "Item 1", "description": "First item"},
                {"id": 2, "name": "Item 2", "description": "Second item"},
                {"id": 3, "name": "Item 3", "description": "Third item"},
            ],
            "total": 3
        }
        response = create_json_response(data)
        return add_cors_headers(req, response)

    except Exception as e:
        logging.error(f"Error processing request: {str(e)}")
        error_response = create_json_response(
            {"error": "Internal server error"},
            status_code=500
        )
        return add_cors_headers(req, error_response)


@app.route(route="api/data", methods=["POST", "OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def create_data(req: func.HttpRequest) -> func.HttpResponse:
    """
    POST /api/data - Creates a new data item.
    Handles CORS preflight (OPTIONS) and actual POST requests.
    """
    logging.info("Processing POST /api/data request")

    # Handle CORS preflight request
    if req.method == "OPTIONS":
        response = func.HttpResponse(status_code=204)
        return add_cors_headers(req, response)

    try:
        # Validate content type to prevent unexpected input
        content_type = req.headers.get("Content-Type", "")
        if "application/json" not in content_type:
            error_response = create_json_response(
                {"error": "Content-Type must be application/json"},
                status_code=415
            )
            return add_cors_headers(req, error_response)

        req_body = req.get_json()

        # Input validation
        if not req_body:
            error_response = create_json_response(
                {"error": "Request body is required"},
                status_code=400
            )
            return add_cors_headers(req, error_response)

        name = req_body.get("name")
        description = req_body.get("description", "")

        if not name or not isinstance(name, str) or len(name) > 255:
            error_response = create_json_response(
                {"error": "Valid 'name' field is required (string, max 255 chars)"},
                status_code=400
            )
            return add_cors_headers(req, error_response)

        if description and (not isinstance(description, str) or len(description) > 1000):
            error_response = create_json_response(
                {"error": "'description' must be a string with max 1000 chars"},
                status_code=400
            )
            return add_cors_headers(req, error_response)

        result = {
            "id": 4,
            "name": name,
            "description": description,
            "message": "Item created successfully"
        }

        response = create_json_response(result, status_code=201)
        return add_cors_headers(req, response)

    except ValueError:
        error_response = create_json_response(
            {"error": "Invalid JSON in request body"},
            status_code=400
        )
        return add_cors_headers(req, error_response)
    except Exception as e:
        logging.error(f"Error processing request: {str(e)}")
        error_response = create_json_response(
            {"error": "Internal server error"},
            status_code=500
        )
        return add_cors_headers(req, error_response)


@app.route(route="api/health", methods=["GET", "OPTIONS"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """
    GET /api/health - Health check endpoint.
    """
    logging.info("Processing GET /api/health request")

    if req.method == "OPTIONS":
        response = func.HttpResponse(status_code=204)
        return add_cors_headers(req, response)

    response = create_json_response({"status": "healthy"})
    return add_cors_headers(req, response)